import{_ as n,c as a,o as l,aj as p}from"./chunks/framework.CynFBi0q.js";const h=JSON.parse('{"title":"第6章 腾讯元器实战：微信生态 AI 智能体","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-agent-dev/chapter_6.md","filePath":"handbook/ai-agent-dev/chapter_6.md","lastUpdated":1781970092000}'),t={name:"handbook/ai-agent-dev/chapter_6.md"};function e(i,s,r,o,d,b){return l(),a("div",null,[...s[0]||(s[0]=[p(`<h1 id="第6章-腾讯元器实战-微信生态-ai-智能体" tabindex="-1">第6章 腾讯元器实战：微信生态 AI 智能体 <a class="header-anchor" href="#第6章-腾讯元器实战-微信生态-ai-智能体" aria-label="Permalink to “第6章 腾讯元器实战：微信生态 AI 智能体”">​</a></h1><p>微信12亿用户，你的AI智能体连不上，等于白做。</p><p>我是怕浪猫，前面聊了 Dify 的企业级 RAG，今天来搞腾讯元器——唯一能原生接入微信生态的 Agent 平台。4个实战案例，从旅行规划到微信支付，帮你把微信这个流量池真正用起来。</p><hr><h2 id="_6-1-腾讯元器平台特性总览" tabindex="-1">6.1 腾讯元器平台特性总览 <a class="header-anchor" href="#_6-1-腾讯元器平台特性总览" aria-label="Permalink to “6.1 腾讯元器平台特性总览”">​</a></h2><p><strong>腾讯元器是什么？</strong></p><p>腾讯元器是腾讯推出的 AI 智能体构建平台，核心卖点是和微信生态的深度集成——公众号、小程序、微信支付、企业微信，一条龙打通。</p><p>核心特性：</p><ol><li><strong>微信原生集成</strong>：直接发布到微信公众号和小程序</li><li><strong>微信支付 MCP</strong>：通过 MCP 协议接入微信支付能力</li><li><strong>跨模态能力</strong>：文本+图片+音频的混合处理</li><li><strong>腾讯混元大模型</strong>：内置腾讯自研大模型</li><li><strong>插件生态</strong>：搜索、图片生成、代码运行等</li></ol><p><strong>和其他平台对比</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>腾讯元器</th><th>Coze</th><th>Dify</th></tr></thead><tbody><tr><td>微信集成</td><td>原生</td><td>需要桥接</td><td>无</td></tr><tr><td>支付能力</td><td>微信支付MCP</td><td>无</td><td>无</td></tr><tr><td>小程序发布</td><td>直接</td><td>不支持</td><td>不支持</td></tr><tr><td>自托管</td><td>不支持</td><td>不支持</td><td>支持</td></tr><tr><td>适合场景</td><td>微信生态</td><td>多平台分发</td><td>企业知识库</td></tr></tbody></table><blockquote><p>如果你的用户在微信上，腾讯元器是唯一正解。其他平台要么连不上，要么连上了体验差。</p></blockquote><hr><h2 id="_6-2-注册登录与界面操作" tabindex="-1">6.2 注册登录与界面操作 <a class="header-anchor" href="#_6-2-注册登录与界面操作" aria-label="Permalink to “6.2 注册登录与界面操作”">​</a></h2><p><strong>注册流程</strong></p><ol><li>访问腾讯元器官网</li><li>使用微信扫码登录</li><li>进入工作台，首次使用有引导</li></ol><p><strong>界面布局</strong></p><ol><li><strong>智能体列表</strong>：管理所有创建的智能体</li><li><strong>插件市场</strong>：浏览和安装插件</li><li><strong>知识库</strong>：上传文档构建知识库</li><li><strong>工作流</strong>：创建和编辑工作流</li><li><strong>发布管理</strong>：管理发布渠道和版本</li></ol><hr><h2 id="_6-3-实战-旅行规划专家" tabindex="-1">6.3 实战：旅行规划专家 <a class="header-anchor" href="#_6-3-实战-旅行规划专家" aria-label="Permalink to “6.3 实战：旅行规划专家”">​</a></h2><p>第一个实战，做一个旅行规划智能体，发布到微信公众号。</p><p><strong>设计思路</strong></p><ol><li>用户在公众号中发送旅行需求</li><li>智能体自动规划行程</li><li>考虑天气、预算、偏好</li><li>生成可分享的行程卡片</li></ol><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个专业的旅行规划师，帮助用户规划旅行行程。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工作流程：</span></span>
<span class="line"><span>1. 了解用户的出发地、目的地、时间、预算、偏好</span></span>
<span class="line"><span>2. 查询目的地的天气和景点信息</span></span>
<span class="line"><span>3. 根据条件和偏好生成行程方案</span></span>
<span class="line"><span>4. 提供详细的日程安排和费用估算</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出格式：</span></span>
<span class="line"><span>- 每日行程：时间+地点+活动+费用</span></span>
<span class="line"><span>- 交通方案：方式+时间+费用</span></span>
<span class="line"><span>- 住宿推荐：名称+价格+评价</span></span>
<span class="line"><span>- 总预算：分项明细</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><strong>发布到公众号</strong></p><ol><li>在智能体设置中选择&quot;发布到微信公众号&quot;</li><li>绑定公众号（需要管理员扫码授权）</li><li>配置触发规则（如：用户发送包含&quot;旅行&quot;的消息时触发）</li><li>发布上线</li></ol><hr><h2 id="_6-4-实战-品牌吉祥物智能体" tabindex="-1">6.4 实战：品牌吉祥物智能体 <a class="header-anchor" href="#_6-4-实战-品牌吉祥物智能体" aria-label="Permalink to “6.4 实战：品牌吉祥物智能体”">​</a></h2><p>第二个实战，做一个品牌吉祥物智能体，让品牌在微信上&quot;活&quot;起来。</p><p><strong>设计思路</strong></p><ol><li>塑造品牌角色的性格和说话方式</li><li>用户可以和吉祥物自然对话</li><li>吉祥物可以推荐产品、解答问题</li><li>朋友圈互动功能</li></ol><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是[品牌名]的吉祥物[角色名]。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>性格特点：</span></span>
<span class="line"><span>- 说话风格：亲切、幽默、偶尔犯傻</span></span>
<span class="line"><span>- 口头禅：&quot;喵~&quot;（每句话结尾可以加）</span></span>
<span class="line"><span>- 禁止：不能说竞品的好话，不能透露公司内部信息</span></span>
<span class="line"><span></span></span>
<span class="line"><span>能力：</span></span>
<span class="line"><span>1. 介绍品牌故事和产品</span></span>
<span class="line"><span>2. 推荐适合用户的产品</span></span>
<span class="line"><span>3. 回答关于品牌和产品的常见问题</span></span>
<span class="line"><span>4. 和用户闲聊，增加品牌好感度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>回答规则：</span></span>
<span class="line"><span>- 每次回答不超过200字</span></span>
<span class="line"><span>- 适当使用口语化表达</span></span>
<span class="line"><span>- 如果用户问了超出能力范围的问题，用品牌角色的方式婉拒</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><blockquote><p>品牌吉祥物不是&quot;套个壳的客服&quot;，而是&quot;有性格的品牌代言人&quot;。性格设定越鲜明，用户越愿意互动。</p></blockquote><hr><h2 id="_6-5-实战-跨模态音乐生成" tabindex="-1">6.5 实战：跨模态音乐生成 <a class="header-anchor" href="#_6-5-实战-跨模态音乐生成" aria-label="Permalink to “6.5 实战：跨模态音乐生成”">​</a></h2><p>第三个实战，做一个跨模态音乐生成智能体——输入文字描述，生成音乐。</p><p><strong>设计思路</strong></p><ol><li>用户描述想要的音乐风格和情绪</li><li>AI 理解音乐意图</li><li>调用音乐生成API</li><li>返回音频文件</li></ol><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个音乐创作助手。根据用户的描述，生成符合要求的音乐。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>理解维度：</span></span>
<span class="line"><span>1. 音乐风格：流行、古典、电子、摇滚、民谣等</span></span>
<span class="line"><span>2. 情绪氛围：欢快、忧伤、紧张、放松等</span></span>
<span class="line"><span>3. 使用场景：咖啡厅、健身、冥想、派对等</span></span>
<span class="line"><span>4. 乐器偏好：钢琴、吉他、合成器等</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工作流程：</span></span>
<span class="line"><span>1. 分析用户的描述，提取音乐参数</span></span>
<span class="line"><span>2. 生成音乐描述词（Music Prompt）</span></span>
<span class="line"><span>3. 调用音乐生成工具</span></span>
<span class="line"><span>4. 返回音频文件和描述</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><hr><h2 id="_6-6-实战-ai-心理咨询师-微信支付-mcp" tabindex="-1">6.6 实战：AI 心理咨询师 + 微信支付 MCP <a class="header-anchor" href="#_6-6-实战-ai-心理咨询师-微信支付-mcp" aria-label="Permalink to “6.6 实战：AI 心理咨询师 + 微信支付 MCP”">​</a></h2><p>第四个实战，做一个AI心理咨询师，集成微信支付实现付费咨询。</p><p><strong>设计思路</strong></p><ol><li>用户在公众号中开始免费咨询</li><li>AI 提供初步的心理疏导</li><li>达到一定对话轮次后，提示付费继续</li><li>通过微信支付 MCP 收取费用</li><li>付费后继续深度咨询</li></ol><p><strong>微信支付 MCP 配置</strong></p><p>MCP（Model Context Protocol）让智能体能调用微信支付能力：</p><ol><li>在腾讯元器的插件配置中启用&quot;微信支付 MCP&quot;</li><li>配置商户号和API密钥</li><li>设置支付商品和价格</li></ol><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个温暖的心理咨询助手。遵循以下原则：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 倾听为先：先理解用户的感受，不要急于给建议</span></span>
<span class="line"><span>2. 共情回应：用&quot;我理解你的感受&quot;等表达建立信任</span></span>
<span class="line"><span>3. 非诊断：明确你不是专业心理医生，不能做诊断</span></span>
<span class="line"><span>4. 安全底线：如果检测到自伤倾向，立即建议拨打心理援助热线</span></span>
<span class="line"><span></span></span>
<span class="line"><span>免费咨询：前3轮对话</span></span>
<span class="line"><span>付费咨询：4轮之后，引导用户付费继续</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>支付流程</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[用户提问] → [AI回答] → [轮次计数]</span></span>
<span class="line"><span>    → 轮次&lt;3 → 继续免费</span></span>
<span class="line"><span>    → 轮次=3 → 提示付费</span></span>
<span class="line"><span>    → 用户确认 → [调用微信支付MCP] → [支付成功] → 继续咨询</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><blockquote><p>AI + 微信支付 = 闭环商业模型。腾讯元器是唯一能原生做到这个闭环的平台。</p></blockquote><hr><h2 id="_6-7-微信生态-ai-应用商业化路径" tabindex="-1">6.7 微信生态 AI 应用商业化路径 <a class="header-anchor" href="#_6-7-微信生态-ai-应用商业化路径" aria-label="Permalink to “6.7 微信生态 AI 应用商业化路径”">​</a></h2><p><strong>4种变现模式</strong></p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>收入预期</th></tr></thead><tbody><tr><td>付费咨询</td><td>按次/按时收费</td><td>中</td></tr><tr><td>知识付费</td><td>AI 课程/问答</td><td>高</td></tr><tr><td>电商导流</td><td>AI 推荐商品，成交后分佣</td><td>高</td></tr><tr><td>企业SaaS</td><td>定制化企业解决方案</td><td>最高</td></tr></tbody></table><p><strong>合规注意事项</strong></p><ol><li><strong>AI 生成内容标识</strong>：根据法规，AI 生成的内容需要标识</li><li><strong>数据安全</strong>：用户对话数据存储和处理需符合《个人信息保护法》</li><li><strong>支付合规</strong>：微信支付需要企业资质</li><li><strong>内容审核</strong>：公众号内容需要通过微信审核</li></ol><p><strong>增长策略</strong></p><ol><li><strong>公众号入口</strong>：通过公众号菜单和文章引流</li><li><strong>小程序裂变</strong>：设计分享机制，用户分享后获得免费额度</li><li><strong>社群运营</strong>：建立微信社群，提供增值服务</li><li><strong>跨平台引流</strong>：从小红书/抖音引流到微信</li></ol><blockquote><p>微信生态的商业化核心是&quot;信任&quot;。AI智能体不是卖货工具，而是建立信任的桥梁。用户信任你的AI，才会信任你推荐的产品。</p></blockquote><hr><p><strong>本章小结</strong></p><table tabindex="0"><thead><tr><th>主题</th><th>核心要点</th></tr></thead><tbody><tr><td>腾讯元器</td><td>唯一原生接入微信生态的Agent平台</td></tr><tr><td>旅行规划</td><td>公众号发布+行程卡片</td></tr><tr><td>品牌吉祥物</td><td>角色化AI+性格设定</td></tr><tr><td>跨模态音乐</td><td>文字→音乐生成</td></tr><tr><td>AI心理咨询</td><td>付费咨询+微信支付MCP</td></tr><tr><td>商业化</td><td>付费咨询/知识付费/电商导流/企业SaaS</td></tr></tbody></table><hr><p>觉得有用？收藏起来，下次直接照抄。</p><p>你在微信生态做过AI应用吗？评论区聊聊你的经验。</p><p>关注怕浪猫，下期我们讲阿里云百炼实战——钉钉+阿里云+数字人，三件套打通企业AI全链路。</p><p>系列进度 6/24</p><p><strong>下章预告：</strong> 第7章我们将深入阿里云百炼平台，从数字人视频生成到多智能体小说创作，从反钓鱼雷达到导购智能体，6个实战案例帮你掌握阿里云生态的AI应用开发。</p>`,73)])])}const g=n(t,[["render",e]]);export{h as __pageData,g as default};
